// // This module implements a 8-bit shift register that shifts right on every clock cycle when enabled. When reset is activated, the shift register should reset to all ones.
module shift_register(
    input               clk         ,   
    input               rst         ,
    input               enable      ,

    output  reg [7:0]   data_out
);

   //shift register
   always @(posedge clk or posedge rst) begin
       if(rst) begin
          data_out <= 8'b0;
       end
       else if(enable) begin
          data_out <= data_out << 1;
       end
   end

endmodule
